from semantic_kernel.functions import kernel_function
from typing import Annotated
import math

class MathPlugin:
    """Tools for mathematical calculations."""

    @kernel_function(name="calculate", description="Evaluate a safe arithmetic expression.")
    def calculate(
        self,
        expression: Annotated[str, "A Python arithmetic expression, e.g. '2 ** 10'"],
    ) -> str:
        allowed = {k: v for k, v in math.__dict__.items() if not k.startswith("_")}
        allowed.update({"abs": abs, "round": round, "min": min, "max": max})
        try:
            return str(eval(expression, {"__builtins__": {}}, allowed))
        except Exception as e:
            return f"Error: {e}"

    @kernel_function(name="word_count", description="Count the words in a text string.")
    def word_count(
        self,
        text: Annotated[str, "The text whose words to count"],
    ) -> str:
        return f"{len(text.split())} words"

class WeatherPlugin:
    """Tools for weather information."""

    @kernel_function(name="get_weather", description="Get the current weather for a city.")
    def get_weather(
        self,
        city: Annotated[str, "City name"],
        unit: Annotated[str, "Temperature unit: celsius or fahrenheit"] = "celsius",
    ) -> str:
        temp = 22 if unit == "celsius" else 71
        return f"{city}: {temp}degree {'C' if unit == 'celsius' else 'F'}"
